import{_ as e,o as a,c as l,Q as i}from"./chunks/framework.6d94f49f.js";const f=JSON.parse('{"title":"Ceph","description":"","frontmatter":{},"headers":[],"relativePath":"DevOps/Ceph/Ceph.md","filePath":"DevOps/Ceph/Ceph.md","lastUpdated":1701334216000}'),t={name:"DevOps/Ceph/Ceph.md"},r=i('<h1 id="ceph" tabindex="-1">Ceph <a class="header-anchor" href="#ceph" aria-label="Permalink to &quot;Ceph&quot;">​</a></h1><ul><li><a href="https://ceph.com/en/discover/" target="_blank" rel="noreferrer">官网</a></li></ul><p>Ceph是一个统一的分布式存储系统，最早起源于Sage就读博士期间的工作（最早的成果于2004年发表），随后贡献给开源社区。其设计初衷是提供较好的性能、可靠性和可扩展性。在经过多年的发展之后，目前已得到众多云计算厂商的支持并被广泛应用。RedHat及OpenStack都可与Ceph整合以支持虚拟机镜像的后端存储。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><h3 id="高性能" tabindex="-1">高性能 <a class="header-anchor" href="#高性能" aria-label="Permalink to &quot;高性能&quot;">​</a></h3><ul><li>摒弃了传统的集中式存储元数据寻址的方案，采用CRUSH算法，数据分布均衡，并行度高</li><li>考虑了容灾域的隔离，能够实现各类负载的副本放置规则，例如跨机房、机架感知等</li><li>能够支持上千个存储节点的规模。支持TB到PB级的数据</li></ul><h3 id="高可用" tabindex="-1">高可用 <a class="header-anchor" href="#高可用" aria-label="Permalink to &quot;高可用&quot;">​</a></h3><ul><li>副本数可以灵活控制</li><li>支持故障域分隔，数据强一致性</li><li>多种故障场景自动进行修复自愈</li><li>没有单点故障，自动管理</li></ul><h3 id="高扩展性" tabindex="-1">高扩展性 <a class="header-anchor" href="#高扩展性" aria-label="Permalink to &quot;高扩展性&quot;">​</a></h3><ul><li>去中心化</li><li>扩展灵活</li><li>随着节点增加，性能线性增长</li></ul><h3 id="特性丰富" tabindex="-1">特性丰富 <a class="header-anchor" href="#特性丰富" aria-label="Permalink to &quot;特性丰富&quot;">​</a></h3><ul><li>支持三种存储接口：对象存储，块设备存储，文件存储</li><li>支持自定义接口，支持多种语言驱动</li></ul>',12),h=[r];function o(n,s,c,d,p,_){return a(),l("div",null,h)}const m=e(t,[["render",o]]);export{f as __pageData,m as default};
